    if SBP_ORDER == 2
        h2inv = 1/h^2
        D2_in = -@SMatrix [h2inv*(-c[i-1]/2 - c[i]/2) h2inv*(c[i-1]/2 + c[i] + c[i+1]/2) h2inv*(-c[i]/2 - c[i+1]/2)]
    elseif SBP_ORDER == 4
        h2inv = 1/h^2
        D2_in = -@SMatrix [
            h2inv*(c[i-2]/0.8e1 - c[i-1]/0.6e1 + c[i]/0.8e1)
            h2inv*(-c[i-2]/0.6e1 - c[i-1]/0.2e1 - c[i]/0.2e1 - c[i+1]/0.6e1)
            h2inv*(c[i-2]/2.4e1 + c[i-1]/1.2e0 + c[i]*0.3/0.4 + c[i+1]/1.2e0 + c[i+2]/2.4e1)
            h2inv*(-c[i-1]/0.6e1 - c[i]/0.2e1 - c[i+1]/0.2e1 - c[i+2]/0.6e1)
            h2inv*(c[i]/0.8e1 - c[i+1]/0.6e1 + c[i+2]/0.8e1)
        ]
    else
        error("SBP_ORDER must be 2 or 4")
    end
    return D2_in
end

@inline function D2_inner_periodic(c::AbstractArray, i::Int, m::Int, h::Real, SBP_ORDER::Int)
    # Helper function to wrap indices periodically
    @inline wrap(idx) = mod1(idx, m)
    
    if SBP_ORDER == 2
        h2inv = 1/h^2
        D2_in = -@SMatrix [
            h2inv*(-c[wrap(i-1)]/2 - c[i]/2) 
            h2inv*(c[wrap(i-1)]/2 + c[i] + c[wrap(i+1)]/2) 
            h2inv*(-c[i]/2 - c[wrap(i+1)]/2)
        ]
    elseif SBP_ORDER == 4
        h2inv = 1/h^2
        D2_in = -@SMatrix [
            h2inv*(c[wrap(i-2)]/0.8e1 - c[wrap(i-1)]/0.6e1 + c[i]/0.8e1)
            h2inv*(-c[wrap(i-2)]/0.6e1 - c[wrap(i-1)]/0.2e1 - c[i]/0.2e1 - c[wrap(i+1)]/0.6e1)
            h2inv*(c[wrap(i-2)]/2.4e1 + c[wrap(i-1)]/1.2e0 + c[i]*0.3/0.4 + c[wrap(i+1)]/1.2e0 + c[wrap(i+2)]/2.4e1)
            h2inv*(-c[wrap(i-1)]/0.6e1 - c[i]/0.2e1 - c[wrap(i+1)]/0.2e1 - c[wrap(i+2)]/0.6e1)
            h2inv*(c[i]/0.8e1 - c[wrap(i+1)]/0.6e1 + c[wrap(i+2)]/0.8e1)
        ]
    else
        error("SBP_ORDER must be 2 or 4")
    end
    return D2_in
end

