        Dmy_∂Ω_S = [[-24/739, 180/739, -720/739, 234/739, 661/1478, 22/739, -45/1478],
                    [0, -8/211, 60/211, -1309/1266, 58/211, 255/422, -58/633],
                    [0, 0, -8/299, 86/897, -375/598, 22/299, 869/1794],
                    [0, 0, 0, 21/502, 94/251, -941/502, 366/251]]*1/hy

        d1x_l = [-354/251, 869/502, -58/251, -45/502]*1/hx
