        d1y_r_central = ([21/502, 94/251, -941/502, 366/251]+[45/502, 58/251, -869/502, 354/251])*1/hy

        quad_term_x = 720 / (251 * hx)
        quad_term_y = 720 / (251 * hy)

        Hx = ones(mx)
        Hx[1] = 251/720
        Hx[2] = 299/240
        Hx[3] = 211/240
        Hx[4] = 739/720
